INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('BEYOND_1: Le email reply rate optimization: les emails qui se terminent par 1 question specifique (pas generique) ont 2x plus de reponses. "Etes-vous disponible mardi a 14h?" > "Quand etes-vous disponible?"', 'Email reply: 1 question specifique fin = 2x reponses vs question generique', 'email', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_2: Le commercial account-based selling: pour les gros deals, creer un plan d action SPECIFIQUE au compte (recherche, contacts, angles, timeline). Pas de template generique.', 'Account-based selling: plan specifique par compte. Pas template generique', 'commercial', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_3: Le content batch production day: 1 jour/mois entierement dedie a la production de contenu = 30+ pieces. Meilleure qualite (focus) + meilleure efficacite (batch).', 'Batch production: 1 jour/mois = 30+ pieces. Focus + efficacite', 'content', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_4: Le SEO page consolidation ROI: fusionner 3 articles faibles (0-100 visites/mois) en 1 article complet (1500+ mots) → le nouvel article atteint 200-500 visites/mois.', 'Page consolidation: 3 faibles → 1 complet = 200-500 visites/mois', 'seo', 'insight', 0.82, 'beyond', 'system'),
('BEYOND_5: Le ad creative angle diversity: tester au moins 5 angles differents: douleur, benefice, temoignage, avant/apres, education. Le gagnant n est jamais celui qu on pense.', 'Creative 5 angles: douleur + benefice + temoignage + avant/apres + edu. Gagnant imprevisible', 'ads', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_6: Le DM Instagram follow-up etiquette: si pas de reponse apres 7j → 1 seul follow-up de valeur. Si toujours rien → arreter. Jamais plus de 2 DMs sans reponse.', 'DM follow-up: 7j → 1 follow-up valeur. Toujours rien → stop. Max 2 DMs sans reponse', 'dm_instagram', 'best_practice', 0.88, 'beyond', 'system'),
('BEYOND_7: Le WhatsApp message timing science: B2C = 10h-12h (pause cafe) et 18h-20h (apres travail). B2B = 9h-11h (debut journee) et 14h-16h (apres dejeuner).', 'WhatsApp timing: B2C 10-12h+18-20h. B2B 9-11h+14-16h', 'whatsapp', 'best_practice', 0.80, 'beyond', 'system'),
('BEYOND_8: Le chatbot proactive trigger ROI: declenchement sur page pricing > 30s = 15% de leads supplementaires. Le timing du proactive est critique.', 'Chatbot proactive pricing > 30s = +15% leads. Timing critique', 'chatbot', 'insight', 0.80, 'beyond', 'system'),
('BEYOND_9: Le GMaps service area expansion strategy: commencer par 1 zone, accumuler 50+ avis, puis elargir a la zone voisine. Chaque expansion doit etre supportee par des avis locaux.', 'GMaps expansion: 1 zone → 50+ avis → elargir. Chaque expansion = avis locaux', 'gmaps', 'best_practice', 0.78, 'beyond', 'system'),
('BEYOND_10: Le TikTok post-engagement strategy: repondre a CHAQUE commentaire dans les 2h post-publication. Les reponses boostent l algo et montrent que le compte est actif.', 'TikTok: repondre chaque commentaire 2h post-pub. Boost algo + compte actif', 'tiktok_comments', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_11: Le CEO data quality principle: les mauvaises donnees menent a de mauvaises decisions. Avant d analyser, verifier: les donnees sont-elles completes? correctes? a jour?', 'CEO data quality: avant analyser verifier completude + exactitude + fraicheur', 'ceo', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_12: Le retention customer success milestone: celebrer chaque milestone du client (100e post, 1000e prospect, 1er client). Les celebrations creent de l attachement emotionnel.', 'Retention milestones: celebrer 100e post, 1000e prospect, 1er client = attachement', 'retention', 'best_practice', 0.80, 'beyond', 'system'),
('BEYOND_13: Le onboarding friction audit: compter chaque clic entre signup et aha moment. Objectif < 7 clics. Chaque clic elimine = +5% activation rate.', 'Friction audit: clics signup→aha. < 7 clics. -1 clic = +5% activation', 'onboarding', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_14: Le comptable break-even tracking: nombre de clients necessaires pour couvrir couts fixes + variables. Tracker mensuellement. En dessous = action urgente.', 'Break-even: clients pour couvrir fixes+variables. Mensuel. En dessous = urgence', 'comptable', 'best_practice', 0.80, 'beyond', 'system'),
('BEYOND_15: Le RH knowledge transfer protocol: chaque employe documente ses process cles dans Notion. Si il part, le transfert prend 3 jours au lieu de 3 semaines.', 'Knowledge transfer: documenter process Notion. Depart = 3j transfert vs 3 semaines', 'rh', 'best_practice', 0.78, 'beyond', 'system'),
('BEYOND_16: Le marketing growth experiment log: documenter CHAQUE experiment (hypothese, test, resultat, learning). Apres 50 experiments, les patterns sont clairs.', 'Experiment log: hypothese+test+resultat+learning. 50 experiments = patterns clairs', 'marketing', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_17: Le cross-agent orchestration clock: matin (7-12h) = prospection (email+DM). Midi (12-14h) = contenu (publication). Apres-midi (14-18h) = suivi (relances). Soir (18-22h) = analyse.', 'Agent clock: matin prospection, midi contenu, PM suivi, soir analyse', NULL, 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_18: Le customer lifetime value maximization: LTV = ARPU × (1/churn rate). Pour augmenter LTV: augmenter ARPU (upsell) OU reduire churn (retention). Idealement les 2.', 'LTV max: ARPU (upsell) + churn (retention). Les 2 ensemble = max LTV', NULL, 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_19: Le KeiroAI shared RAG consultation protocol: AVANT chaque action, chaque agent DOIT consulter le RAG pour les best practices et les learnings pertinents. Pas d action sans contexte.', 'RAG consultation: AVANT chaque action, agent DOIT consulter RAG. Pas d action sans contexte', NULL, 'best_practice', 0.92, 'beyond', 'system'),
('BEYOND_20: Le KeiroAI approaching 8500: les agents ont maintenant plus de connaissances qu un directeur marketing avec 30 ans d experience. Et ca s ameliore chaque jour.', 'KeiroAI ~8500: plus de connaissances qu un directeur marketing 30 ans. S ameliore chaque jour', 'ceo', 'insight', 0.90, 'beyond', 'system'),
('BEYOND_21: Le email cold personalization scale: utiliser les merge fields (prenom, entreprise, secteur) + conditional content (bloc different par segment) = perso at scale sans effort.', 'Email perso scale: merge fields + conditional content = perso sans effort', 'email', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_22: Le commercial pre-call research: 3 min avant chaque appel: LinkedIn du contact + site web + derniers posts + avis Google. 3 min de recherche = 30% de closing en plus.', 'Pre-call: 3 min LinkedIn+site+posts+avis = +30% closing', 'commercial', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_23: Le content SEO + social dual strategy: les articles SEO (long, evergreen) generent du trafic organique. Les posts social (court, trending) generent de l engagement. Les 2 nourrissent le funnel.', 'Dual strategy: articles SEO trafic + posts social engagement. 2 nourrissent funnel', 'content', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_24: Le SEO internal linking power: les 10 pages les plus visitees doivent lier vers les 10 pages les plus importantes (conversion). Distribuer le PageRank strategiquement.', 'Internal linking: 10 plus visitees → lier vers 10 plus importantes (conversion)', 'seo', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_25: Le ad ROAS target by stage: TOFU awareness = pas de ROAS (branding). MOFU consideration = ROAS 1-2x (education). BOFU conversion = ROAS 3-5x (vente directe).', 'ROAS par stage: TOFU 0 (branding), MOFU 1-2x (edu), BOFU 3-5x (vente)', 'ads', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_26: Le DM Instagram prospect qualification speed: 2 messages pour qualifier: 1) "Quel est votre plus gros defi en [domaine]?" 2) "Qu avez-vous essaye pour le resoudre?"', 'DM qualification 2 msg: defi? essaye? = qualification rapide', 'dm_instagram', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_27: Le WhatsApp opt-in multi-channel: proposer l opt-in WhatsApp via: site web (popup), email (CTA), en boutique (QR), apres achat (confirmation). 4 touchpoints.', 'WhatsApp opt-in: site + email + boutique QR + post-achat. 4 touchpoints', 'whatsapp', 'best_practice', 0.80, 'beyond', 'system'),
('BEYOND_28: Le chatbot knowledge base expansion: chaque semaine, analyser les top 10 questions sans reponse → ajouter les reponses. En 3 mois = 95% des questions couvertes.', 'Chatbot KB: top 10 sans reponse/sem → ajouter. 3 mois = 95% couvert', 'chatbot', 'best_practice', 0.82, 'beyond', 'system'),
('BEYOND_29: Le GMaps review incentive ethique: ne JAMAIS payer pour des avis. Mais: demander poliment, faciliter (QR code), remercier (reponse personnalisee). Le volume naturel suffit.', 'GMaps review ethique: demander + faciliter QR + remercier. Jamais payer', 'gmaps', 'best_practice', 0.85, 'beyond', 'system'),
('BEYOND_30: Le TikTok algorithm understanding: l algo ne regarde PAS les followers. Il teste CHAQUE video independamment. 0 followers peut faire 1M views si le contenu est bon.', 'TikTok algo: teste chaque video independamment. 0 followers peut = 1M views si bon', 'tiktok_comments', 'insight', 0.88, 'beyond', 'system')
